import os

def delete_uploaded_file(filename):
    uploads_dir = 'uploads/'
    file_path = os.path.join(uploads_dir, filename)
    
    if os.path.exists(file_path):
        os.remove(file_path)
        return f"{filename} deleted successfully."
    else:
        return f"File '{filename}' not found."